1	import "server-only";
2	
3	import { nanoid } from "@repo/lib";
4	import {
5	  captureException,
6	  getActiveSpan,
7	  SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN,
8	  SEMANTIC_ATTRIBUTE_SENTRY_SOURCE,
9	  startSpan,
10	  withIsolationScope,
11	} from "@sentry/core";
12	import type { TRPCError } from "@trpc/server";
13	import { getHTTPStatusCodeFromError } from "@trpc/server/http";
14	
15	import { log } from "./log/next";
16	import { emitJournal, withRequestContext } from "./request";
17	
18	type AuthFields = Record<string, unknown>;
19	
20	/** Minimal shape of tRPC's MiddlewareResult — just the fields we inspect. */
21	interface MiddlewareResultLike {
22	  error?: TRPCError;
23	  ok: boolean;
24	}
25	
26	interface CreateObservabilityMiddlewareOptions<TCtx> {
27	  /** Extract auth-related fields from the tRPC context for log enrichment and request context. */
28	  extractAuth: (ctx: TCtx) => AuthFields;
29	  /** Whether the server is in development mode (enables artificial latency). */
30	  isDev: boolean;
31	}
32	
33	/**
34	 * Create a tRPC observability middleware that consolidates:
35	 * - Sentry isolation scope + span creation (replaces trpcMiddleware)
36	 * - Error classification via HTTP status derivation (no constants needed)
37	 * - Selective Sentry capture (server errors only, with tags)
38	 * - Structured logging with trace ID correlation
39	 * - Request journal emission
40	 */
41	export function createObservabilityMiddleware<TCtx>(
42	  opts: CreateObservabilityMiddlewareOptions<TCtx>
43	) {
44	  return async <TResult extends MiddlewareResultLike>({
45	    next,
46	    path,
47	    ctx,
48	    type,
49	    getRawInput,
50	  }: {
51	    next: () => Promise<TResult>;
52	    path: string;
53	    ctx: TCtx;
54	    type: string;
55	    getRawInput: () => Promise<unknown>;
56	  }): Promise<TResult> => {
57	    if (opts.isDev) {
58	      const waitMs = Math.floor(Math.random() * 400) + 100;
59	      await new Promise((resolve) => setTimeout(resolve, waitMs));
60	    }
61	
62	    const authFields = opts.extractAuth(ctx);
63	
64	    return withIsolationScope(async (scope) => {
65	      // Attach tRPC context to Sentry scope (replaces trpcMiddleware)
66	      const trpcContext: Record<string, unknown> = {
67	        procedure_path: path,
68	        procedure_type: type,
69	      };
70	
71	      try {
72	        const rawInput = await getRawInput();
73	        if (rawInput !== undefined) {
74	          trpcContext.input = rawInput;
75	        }
76	      } catch {
77	        // getRawInput can throw if input parsing failed — safe to ignore
78	      }
79	
80	      scope.setContext("trpc", trpcContext);
81	
82	      return startSpan(
83	        {
84	          name: `trpc/${path}`,
85	          op: "rpc.server",
86	          attributes: {
87	            [SEMANTIC_ATTRIBUTE_SENTRY_SOURCE]: "route",
88	            [SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN]: "auto.rpc.trpc",
89	          },
90	        },
91	        async () => {
92	          // Get Sentry trace ID for log↔trace correlation
93	          const span = getActiveSpan();
94	          const traceId = span?.spanContext().traceId;
95	
96	          const requestId = nanoid();
97	          const { result, journal, durationMs } = await withRequestContext(
98	            { requestId, ...(traceId && { traceId }), ...authFields },
99	            () => next()
100	          );
101	
102	          const meta = {
103	            path,
104	            type,
105	            durationMs,
106	            ok: result.ok,
107	            requestId,
108	            ...(traceId && { traceId }),
109	            ...(!result.ok && result.error && { errorCode: result.error.code }),
110	            ...authFields,
111	          };
112	
113	          if (result.ok) {
114	            log.info("[trpc] ok", meta);
115	          } else if (result.error) {
116	            const httpStatus = getHTTPStatusCodeFromError(result.error);
117	
118	            if (httpStatus >= 500) {
119	              log.error("[trpc] server error", meta);
120	              scope.setTag("trpc.path", path);
121	              scope.setTag("trpc.type", type);
122	              scope.setTag("trpc.error_code", result.error.code);
123	              scope.setExtra("durationMs", durationMs);
124	              scope.setExtra("requestId", requestId);
125	              // Send the original error for better Sentry grouping and titles.
126	              // TRPCError wraps raw Errors with a generic message; the cause has the real info.
127	              const reportedError =
128	                result.error.code === "INTERNAL_SERVER_ERROR" &&
129	                result.error.cause instanceof Error
130	                  ? result.error.cause
131	                  : result.error;
132	
133	              captureException(reportedError, {
134	                mechanism: {
135	                  handled: false,
136	                  type: "auto.rpc.trpc.middleware",
137	                },
138	              });
139	            } else {
140	              log.info("[trpc] client error", meta);
141	            }
142	          }
143	
144	          emitJournal(journal, { path, durationMs, ok: result.ok });
145	
146	          return result;
147	        }
148	      );
149	    });
150	  };
151	}
